+    let (sum_cos, sum_sin) = phase_diffs
+        .iter()
+        .fold((0.0_f32, 0.0_f32), |(c, s), &dp| {
+            (c + dp.cos(), s + dp.sin())
+        });
+    let n = phase_diffs.len() as f32;
+    ((sum_cos / n).powi(2) + (sum_sin / n).powi(2)).sqrt()
+}
