+        // Constant velocity = zero acceleration → no pre-movement
+        for frame in 0..20_u64 {
+            let pos = frame as f32 * 0.01; // constant velocity
+            let emb = vec![1.0 + pos, 0.0, 0.0, 0.0];
+            let signal = detector.update(&emb, frame * 50_000).unwrap();
+            assert!(
+                !signal.detected,
