+
+    #[test]
+    fn test_window_size_limit() {
+        let config = IntentionConfig {
+            window_size: 5,
+            ..make_config()
+        };
+        let mut detector = IntentionDetector::new(config).unwrap();
+
+        for frame in 0..10_u64 {
